import{c as a,Q as n,j as i,m as t}from"./chunks/framework.BXc4yaFE.js";const g=JSON.parse('{"title":"Harness Engineering for Language Agents: The Harness Layer as Control, Agency, and Runtime","description":"","frontmatter":{"title":"Harness Engineering for Language Agents: The Harness Layer as Control, Agency, and Runtime","authors":"Chaoyue He, Xin Zhou, Di Wang, Hong Xu, Wei Liu, Chunyan Miao","published":"2026-04-23T00:00:00.000Z","source":"https://www.preprints.org/manuscript/202603.1756.v2"},"headers":[],"relativePath":"research/papers/2026-04-23-harness-engineering-language-agents-car.md","filePath":"research/papers/2026-04-23-harness-engineering-language-agents-car.md","lastUpdated":1779901665000}'),r={name:"research/papers/2026-04-23-harness-engineering-language-agents-car.md"};function s(o,e,l,c,p,u){return n(),i("div",null,[...e[0]||(e[0]=[t(`<h1 id="harness-engineering-for-language-agents-the-harness-layer-as-control-agency-and-runtime" tabindex="-1">Harness Engineering for Language Agents: The Harness Layer as Control, Agency, and Runtime <a class="header-anchor" href="#harness-engineering-for-language-agents-the-harness-layer-as-control-agency-and-runtime" aria-label="Permalink to &quot;Harness Engineering for Language Agents: The Harness Layer as Control, Agency, and Runtime&quot;">​</a></h1><p><strong>Authors</strong>: Chaoyue He, Xin Zhou, Di Wang, Hong Xu, Wei Liu, Chunyan Miao<br><strong>Published</strong>: April 23, 2026<br><strong>Source</strong>: <a href="https://www.preprints.org/manuscript/202603.1756.v2" target="_blank" rel="noreferrer">https://www.preprints.org/manuscript/202603.1756.v2</a><br><strong>DOI</strong>: 10.20944/preprints202603.1756.v2</p><h2 id="abstract" tabindex="-1">Abstract <a class="header-anchor" href="#abstract" aria-label="Permalink to &quot;Abstract&quot;">​</a></h2><p>Language agents that operate via tools, files, browsers, APIs, and sustained sessions depend on more than base model quality or prompting alone. Their dependability stems from a &quot;harness layer&quot;—the infrastructure determining which instructions hold authority, available actions, state persistence, and failure management across time. This paper argues this infrastructure warrants explicit academic treatment. The authors present a working decomposition framing the harness layer as <strong>control, agency, and runtime (CAR)</strong>; position harness engineering within the progression from software engineering through prompt and context engineering; and examine <strong>63</strong> relevant works, revealing a notable gap between academic literature and public engineering documentation. The paper contends that numerous documented agent improvements may be <strong>harness-dependent</strong> rather than purely model-driven, and proposes <strong>HarnessCard</strong> as a straightforward disclosure mechanism. Drawing on papers, benchmarks, protocols, and engineering materials current through <strong>April 21, 2026</strong>, the authors advocate that agent progress reporting should encompass the harness layer converting capability into regulated action.</p><h2 id="keywords" tabindex="-1">Keywords <a class="header-anchor" href="#keywords" aria-label="Permalink to &quot;Keywords&quot;">​</a></h2><p>Language agents; harness engineering; agent harness; control agency runtime (CAR); agent evaluation; prompt engineering; context engineering; HarnessCard; scaffolding; LLM agents; tool use</p><h2 id="_1-introduction" tabindex="-1">1. Introduction <a class="header-anchor" href="#_1-introduction" aria-label="Permalink to &quot;1. Introduction&quot;">​</a></h2><h3 id="_1-1-the-infrastructure-problem" tabindex="-1">1.1 The Infrastructure Problem <a class="header-anchor" href="#_1-1-the-infrastructure-problem" aria-label="Permalink to &quot;1.1 The Infrastructure Problem&quot;">​</a></h3><p>Language agents have become central to autonomous software engineering, information retrieval, and decision support. Yet despite rapid progress in model capabilities, agent reliability remains uneven. Current approaches treat the harness layer—the infrastructure governing agent execution—as implementation detail rather than an explicit research object.</p><p>The core claim: <strong>agent performance improvements often stem from harness changes rather than model capability alone</strong>. Systems like SWE-agent demonstrate that interface redesign substantially affects performance. Yet this infrastructure remains underspecified in academic literature compared to engineering practice.</p><h3 id="_1-2-visibility-asymmetry" tabindex="-1">1.2 Visibility Asymmetry <a class="header-anchor" href="#_1-2-visibility-asymmetry" aria-label="Permalink to &quot;1.2 Visibility Asymmetry&quot;">​</a></h3><p>Academic papers emphasize model quality and prompt engineering. Engineering documentation from frontier organizations (Anthropic, OpenAI) foregrounds runtime governance, memory management, and control mechanisms. This asymmetry obscures reproducibility and cumulative progress.</p><h3 id="_1-3-research-scope" tabindex="-1">1.3 Research Scope <a class="header-anchor" href="#_1-3-research-scope" aria-label="Permalink to &quot;1.3 Research Scope&quot;">​</a></h3><p>This paper:</p><ul><li>Proposes the CAR decomposition as a working framework for analyzing harness structure</li><li>Conducts a descriptive audit of 63 relevant works published through April 2026</li><li>Identifies patterns in control, agency, and runtime design</li><li>Proposes HarnessCard as a transparency mechanism</li><li>Advocates for explicit harness-layer research</li></ul><h2 id="_2-the-car-framework-control-agency-runtime" tabindex="-1">2. The CAR Framework: Control, Agency, Runtime <a class="header-anchor" href="#_2-the-car-framework-control-agency-runtime" aria-label="Permalink to &quot;2. The CAR Framework: Control, Agency, Runtime&quot;">​</a></h2><h3 id="_2-1-control-layer-c" tabindex="-1">2.1 Control Layer (C) <a class="header-anchor" href="#_2-1-control-layer-c" aria-label="Permalink to &quot;2.1 Control Layer (C)&quot;">​</a></h3><p><strong>Definition</strong>: Durable artifacts encoding behavioral constraints before execution.</p><p><strong>Exemplars</strong>:</p><ul><li>Repository maps and navigation structures</li><li>AGENTS.md files specifying agent roles and capabilities</li><li>Architectural rules and permission policies</li><li>Tool descriptions and interface schemas</li><li>Test suites and validation procedures</li><li>Linting rules and static checks</li></ul><p><strong>Key property</strong>: Control is linguistic and persistent. It shapes what agents can do by explicitly restricting the space of permissible actions.</p><p><strong>Examples in practice</strong>:</p><ul><li>Anthropic&#39;s documented agent guidelines constrain tool access per role</li><li>OpenAI&#39;s system prompts embed behavioral policies</li><li>SWE-agent&#39;s repository interface controls which files agents access</li></ul><h3 id="_2-2-agency-layer-a" tabindex="-1">2.2 Agency Layer (A) <a class="header-anchor" href="#_2-2-agency-layer-a" aria-label="Permalink to &quot;2.2 Agency Layer (A)&quot;">​</a></h3><p><strong>Definition</strong>: The action substrates and interfaces through which agents interact with systems.</p><p><strong>Exemplars</strong>:</p><ul><li>Code execution environments (sandboxed, unsandboxed)</li><li>Browser automation interfaces</li><li>Tool APIs and their schemas</li><li>Orchestrator-worker communication patterns</li><li>Reviewer roles and approval workflows</li><li>Concrete interface definitions (e.g., action schemas in ReAct)</li></ul><p><strong>Key property</strong>: Agency defines the &quot;shape&quot; of possible actions. An agent with access to a Python REPL has different agency than one with access only to web search.</p><p><strong>Examples in practice</strong>:</p><ul><li>SWE-agent&#39;s command-line interface differs from CoOp&#39;s browser interface</li><li>Retrieval-augmented generation (RAG) agents have different agency than repository-browsing agents</li><li>Approval workflows reduce agency but increase oversight</li></ul><h3 id="_2-3-runtime-layer-r" tabindex="-1">2.3 Runtime Layer (R) <a class="header-anchor" href="#_2-3-runtime-layer-r" aria-label="Permalink to &quot;2.3 Runtime Layer (R)&quot;">​</a></h3><p><strong>Definition</strong>: Time-based governance structures that maintain system coherence over extended execution.</p><p><strong>Exemplars</strong>:</p><ul><li>Context assembly and optimization</li><li>Memory management (working, episodic, semantic)</li><li>State persistence and checkpointing</li><li>Retry strategies and backtracking</li><li>Approval workflows and budget enforcement</li><li>Trace collection and observability</li></ul><p><strong>Key property</strong>: Runtime is the execution layer. It determines how agents navigate long-horizon tasks while managing finite resources (context, compute, time).</p><p><strong>Examples in practice</strong>:</p><ul><li>Context compaction strategies determine when agents lose information</li><li>Memory systems affect what agents &quot;remember&quot; across sessions</li><li>Retry budgets affect failure recovery</li><li>Checkpointing enables recovery from transient failures</li></ul><h2 id="_3-harness-sensitivity-why-attribution-matters" tabindex="-1">3. Harness Sensitivity: Why Attribution Matters <a class="header-anchor" href="#_3-harness-sensitivity-why-attribution-matters" aria-label="Permalink to &quot;3. Harness Sensitivity: Why Attribution Matters&quot;">​</a></h2><h3 id="_3-1-core-claim" tabindex="-1">3.1 Core Claim <a class="header-anchor" href="#_3-1-core-claim" aria-label="Permalink to &quot;3.1 Core Claim&quot;">​</a></h3><p>Many reported agent performance gains derive from harness improvements rather than model capability increases alone.</p><p><strong>Evidence</strong>:</p><ul><li>SWE-agent&#39;s command-line interface redesign improved performance by ~40% without model changes</li><li>OS-Symphony&#39;s migration from code-based to natural-language harness representation shifted performance profiles</li><li>Meta-Harness demonstrates that discovered harness optimizations transfer across models</li></ul><h3 id="_3-2-attribution-challenge" tabindex="-1">3.2 Attribution Challenge <a class="header-anchor" href="#_3-2-attribution-challenge" aria-label="Permalink to &quot;3.2 Attribution Challenge&quot;">​</a></h3><p>When a paper reports performance improvement, the gain could stem from:</p><ol><li>Model capability improvement (true capability gain)</li><li>Harness redesign (infrastructure change)</li><li>Task-specific tuning (narrow optimization)</li><li>Interaction effects (multiple factors combined)</li></ol><p><strong>Current practice</strong>: Papers typically report only improvement magnitude, obscuring source.</p><p><strong>Proposed solution</strong>: Disclose harness details explicitly, enabling readers to judge attribution.</p><h3 id="_3-3-reproducibility-implications" tabindex="-1">3.3 Reproducibility Implications <a class="header-anchor" href="#_3-3-reproducibility-implications" aria-label="Permalink to &quot;3.3 Reproducibility Implications&quot;">​</a></h3><p>Without harness specification:</p><ul><li>Reproducing results requires reverse-engineering the infrastructure</li><li>Comparing methods becomes difficult (model vs. harness confounded)</li><li>Insights fail to generalize to other settings</li></ul><p>With harness specification:</p><ul><li>Reproducibility improves substantially</li><li>Attribution becomes clearer</li><li>Insights can be reused across projects</li></ul><h2 id="_4-evidence-audit-63-in-scope-works" tabindex="-1">4. Evidence Audit: 63 In-Scope Works <a class="header-anchor" href="#_4-evidence-audit-63-in-scope-works" aria-label="Permalink to &quot;4. Evidence Audit: 63 In-Scope Works&quot;">​</a></h2><h3 id="_4-1-methodology" tabindex="-1">4.1 Methodology <a class="header-anchor" href="#_4-1-methodology" aria-label="Permalink to &quot;4.1 Methodology&quot;">​</a></h3><p>The authors conducted a descriptive audit of 75 total sources, designating 63 as in-scope harness-relevant works:</p><ul><li><strong>38 academic papers or benchmarks</strong> focused on agent evaluation, interface design, or system architecture</li><li><strong>25 engineering notes, protocol documents, or technical articles</strong> from frontier organizations</li></ul><p><strong>Timeline</strong>: Bias toward recent work (51 of 63 from 2024-2026)</p><h3 id="_4-2-key-findings" tabindex="-1">4.2 Key Findings <a class="header-anchor" href="#_4-2-key-findings" aria-label="Permalink to &quot;4.2 Key Findings&quot;">​</a></h3><p><strong>Academic literature</strong> emphasizes:</p><ul><li>Interface design and evaluation protocols</li><li>Agent performance metrics</li><li>Model capability advancement</li><li>Prompt engineering techniques</li></ul><p><strong>Engineering documentation</strong> foregrounds:</p><ul><li>Runtime control and state management</li><li>Memory architectures</li><li>Safety governance mechanisms</li><li>Context optimization strategies</li></ul><p><strong>Gap interpretation</strong>: Harness engineering remains more visible in practice than in formal venues, suggesting it is underrepresented as a research object.</p><h3 id="_4-3-representative-works" tabindex="-1">4.3 Representative Works <a class="header-anchor" href="#_4-3-representative-works" aria-label="Permalink to &quot;4.3 Representative Works&quot;">​</a></h3><p><strong>Control-layer focus</strong>:</p><ul><li>SWE-agent: Command-line interface design</li><li>Anthropic&#39;s agent safety guidelines</li><li>OpenAI&#39;s system prompt documentation</li></ul><p><strong>Agency-layer focus</strong>:</p><ul><li>ReAct: Action schema design</li><li>CoOp: Browser automation interface</li><li>General Agent Evaluation: Interface standardization</li></ul><p><strong>Runtime-layer focus</strong>:</p><ul><li>Trajectory-level auditing: Execution tracing</li><li>Context-compaction strategies: Token-efficient long-horizon execution</li><li>Memory systems: Persistent knowledge across sessions</li></ul><h2 id="_5-design-patterns-and-failure-modes" tabindex="-1">5. Design Patterns and Failure Modes <a class="header-anchor" href="#_5-design-patterns-and-failure-modes" aria-label="Permalink to &quot;5. Design Patterns and Failure Modes&quot;">​</a></h2><h3 id="_5-1-repository-coding-agents" tabindex="-1">5.1 Repository Coding Agents <a class="header-anchor" href="#_5-1-repository-coding-agents" aria-label="Permalink to &quot;5.1 Repository Coding Agents&quot;">​</a></h3><p><strong>Typical CAR configuration</strong>:</p><ul><li><strong>Control</strong>: File-level access policies, safe-edit enforcements</li><li><strong>Agency</strong>: Command-line shell, file browser, code editor</li><li><strong>Runtime</strong>: Checkpoint after each edit, retry with modified strategy</li></ul><p><strong>Failure mode</strong>: Context drift—as session length increases, agents lose awareness of repository structure.</p><h3 id="_5-2-browser-agents" tabindex="-1">5.2 Browser Agents <a class="header-anchor" href="#_5-2-browser-agents" aria-label="Permalink to &quot;5.2 Browser Agents&quot;">​</a></h3><p><strong>Typical CAR configuration</strong>:</p><ul><li><strong>Control</strong>: Visual feedback rules, screenshot interpretation guidelines</li><li><strong>Agency</strong>: Viewport navigation, element locator interface</li><li><strong>Runtime</strong>: Screenshot-based context, visual state tracking</li></ul><p><strong>Failure mode</strong>: Verifier overfitting—agents learn to exploit evaluation signals rather than solve underlying tasks.</p><h3 id="_5-3-enterprise-support-agents" tabindex="-1">5.3 Enterprise Support Agents <a class="header-anchor" href="#_5-3-enterprise-support-agents" aria-label="Permalink to &quot;5.3 Enterprise Support Agents&quot;">​</a></h3><p><strong>Typical CAR configuration</strong>:</p><ul><li><strong>Control</strong>: Role-based access control, escalation rules</li><li><strong>Agency</strong>: Ticketing systems, knowledge base search</li><li><strong>Runtime</strong>: Multi-turn conversation memory, approval workflows</li></ul><p><strong>Failure mode</strong>: Policy violation—agents exceed authorization boundaries during extended conversations.</p><h2 id="_6-harnesscard-proposed-disclosure-standard" tabindex="-1">6. HarnessCard: Proposed Disclosure Standard <a class="header-anchor" href="#_6-harnesscard-proposed-disclosure-standard" aria-label="Permalink to &quot;6. HarnessCard: Proposed Disclosure Standard&quot;">​</a></h2><h3 id="_6-1-motivation" tabindex="-1">6.1 Motivation <a class="header-anchor" href="#_6-1-motivation" aria-label="Permalink to &quot;6.1 Motivation&quot;">​</a></h3><p>Current practices obscure harness details, making reproducibility and comparison difficult. HarnessCard provides a lightweight disclosure template.</p><h3 id="_6-2-required-fields" tabindex="-1">6.2 Required Fields <a class="header-anchor" href="#_6-2-required-fields" aria-label="Permalink to &quot;6.2 Required Fields&quot;">​</a></h3><p>A HarnessCard specifies:</p><h4 id="base-model" tabindex="-1">Base Model <a class="header-anchor" href="#base-model" aria-label="Permalink to &quot;Base Model&quot;">​</a></h4><ul><li>Model name and version</li><li>Decoding parameters (temperature, top-p, max tokens)</li><li>Fine-tuning or prompt-engineering applied</li></ul><h4 id="control-artifacts" tabindex="-1">Control Artifacts <a class="header-anchor" href="#control-artifacts" aria-label="Permalink to &quot;Control Artifacts&quot;">​</a></h4><ul><li>AGENTS.md or role specification</li><li>Tool descriptions and schemas</li><li>Architectural rules and constraints</li><li>Safety policies and permission models</li></ul><h4 id="runtime-policies" tabindex="-1">Runtime Policies <a class="header-anchor" href="#runtime-policies" aria-label="Permalink to &quot;Runtime Policies&quot;">​</a></h4><ul><li>Memory architecture (working, episodic, semantic)</li><li>Context assembly strategy</li><li>Checkpointing and retry policies</li><li>Budget constraints (tokens, compute, wall-clock time)</li></ul><h4 id="action-substrate" tabindex="-1">Action Substrate <a class="header-anchor" href="#action-substrate" aria-label="Permalink to &quot;Action Substrate&quot;">​</a></h4><ul><li>Available tools (shell, browser, APIs, etc.)</li><li>Execution environment (sandboxed, etc.)</li><li>Communication protocols</li><li>Error handling and recovery</li></ul><h4 id="execution-topology" tabindex="-1">Execution Topology <a class="header-anchor" href="#execution-topology" aria-label="Permalink to &quot;Execution Topology&quot;">​</a></h4><ul><li>Single-agent vs. multi-agent orchestration</li><li>Planner-executor separation</li><li>Reviewer roles and approval workflows</li></ul><h4 id="feedback-mechanisms" tabindex="-1">Feedback Mechanisms <a class="header-anchor" href="#feedback-mechanisms" aria-label="Permalink to &quot;Feedback Mechanisms&quot;">​</a></h4><ul><li>How agents observe outcomes</li><li>Error signals and their interpretation</li><li>Success/failure signals</li></ul><h4 id="governance-structures" tabindex="-1">Governance Structures <a class="header-anchor" href="#governance-structures" aria-label="Permalink to &quot;Governance Structures&quot;">​</a></h4><ul><li>Human oversight points</li><li>Escalation triggers</li><li>Audit trails and observability</li></ul><h4 id="observability-and-evaluation" tabindex="-1">Observability and Evaluation <a class="header-anchor" href="#observability-and-evaluation" aria-label="Permalink to &quot;Observability and Evaluation&quot;">​</a></h4><ul><li>Metrics tracked</li><li>Failure categories monitored</li><li>Evaluation protocols used</li></ul><h3 id="_6-3-template-example" tabindex="-1">6.3 Template Example <a class="header-anchor" href="#_6-3-template-example" aria-label="Permalink to &quot;6.3 Template Example&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>## HarnessCard</span></span>
<span class="line"><span></span></span>
<span class="line"><span>**Model**: Claude 3.5 Sonnet, temperature=0.7, max_tokens=2048</span></span>
<span class="line"><span></span></span>
<span class="line"><span>**Control**:</span></span>
<span class="line"><span>- Tool access: File read/write (restricted to /project/), CLI execution (command whitelist)</span></span>
<span class="line"><span>- Safety policy: Approval required for destructive operations</span></span>
<span class="line"><span>- Test suite: Pre-commit linting enforced</span></span>
<span class="line"><span></span></span>
<span class="line"><span>**Runtime**:</span></span>
<span class="line"><span>- Memory: Session history (last 10K tokens) + persistent notes</span></span>
<span class="line"><span>- Context strategy: Compression at 80% window utilization</span></span>
<span class="line"><span>- Retry budget: 3 attempts per failed action</span></span>
<span class="line"><span></span></span>
<span class="line"><span>**Agency**:</span></span>
<span class="line"><span>- Shell: /bin/bash with command restrictions</span></span>
<span class="line"><span>- File system: Project directory only, no system directories</span></span>
<span class="line"><span>- APIs: Internal service mesh, authentication via token</span></span>
<span class="line"><span></span></span>
<span class="line"><span>**Topology**:</span></span>
<span class="line"><span>- Single agent planning and execution</span></span>
<span class="line"><span>- No multi-agent orchestration</span></span>
<span class="line"><span>- Manual approval for large code changes</span></span>
<span class="line"><span></span></span>
<span class="line"><span>**Feedback**:</span></span>
<span class="line"><span>- Success: Task completion signal from external validation</span></span>
<span class="line"><span>- Failure: Error messages from tool execution</span></span>
<span class="line"><span>- Observability: Full trace logging</span></span>
<span class="line"><span></span></span>
<span class="line"><span>**Governance**:</span></span>
<span class="line"><span>- Human review: Required for changes affecting production</span></span>
<span class="line"><span>- Audit: All operations logged to central system</span></span>
<span class="line"><span>- Escalation: Complex tasks escalated to senior engineers</span></span>
<span class="line"><span></span></span>
<span class="line"><span>**Evaluation**:</span></span>
<span class="line"><span>- Metric: Task success rate on benchmark suite</span></span>
<span class="line"><span>- Benchmark: SWE-bench Verified (500 tasks)</span></span>
<span class="line"><span>- Failure categories: Timeout, syntax error, logic error</span></span></code></pre></div><h2 id="_7-research-agenda" tabindex="-1">7. Research Agenda <a class="header-anchor" href="#_7-research-agenda" aria-label="Permalink to &quot;7. Research Agenda&quot;">​</a></h2><h3 id="_7-1-control-as-executable-specification" tabindex="-1">7.1 Control as Executable Specification <a class="header-anchor" href="#_7-1-control-as-executable-specification" aria-label="Permalink to &quot;7.1 Control as Executable Specification&quot;">​</a></h3><p><strong>Direction</strong>: Treat control artifacts as first-class research objects.</p><p><strong>Questions</strong>:</p><ul><li>How do different control formulations (natural language vs. code) affect agent behavior?</li><li>Which control abstractions are most reusable across agent types?</li><li>Can control artifacts be automatically synthesized from task descriptions?</li></ul><p><strong>Exemplar</strong>: Meta-Harness demonstrates that discovered harnesses transfer across models.</p><h3 id="_7-2-agency-as-interface-design" tabindex="-1">7.2 Agency as Interface Design <a class="header-anchor" href="#_7-2-agency-as-interface-design" aria-label="Permalink to &quot;7.2 Agency as Interface Design&quot;">​</a></h3><p><strong>Direction</strong>: Systematize agency design as a research domain.</p><p><strong>Questions</strong>:</p><ul><li>How do different action substrates (shell vs. browser vs. API) affect success rates?</li><li>What interface abstractions minimize context overhead?</li><li>Can agents learn to use novel interfaces without explicit training?</li></ul><p><strong>Exemplar</strong>: SWE-agent&#39;s command-line interface redesign improved performance substantially.</p><h3 id="_7-3-runtime-as-scientific-variable" tabindex="-1">7.3 Runtime as Scientific Variable <a class="header-anchor" href="#_7-3-runtime-as-scientific-variable" aria-label="Permalink to &quot;7.3 Runtime as Scientific Variable&quot;">​</a></h3><p><strong>Direction</strong>: Measure runtime effects independently from model and control effects.</p><p><strong>Questions</strong>:</p><ul><li>How do different memory architectures affect long-horizon performance?</li><li>What context-compaction strategies are optimal for different task types?</li><li>How do retry policies interact with control and agency?</li></ul><p><strong>Exemplar</strong>: Trajectory-level auditing separates execution effects from capability effects.</p><h3 id="_7-4-normalization-of-harness-reporting" tabindex="-1">7.4 Normalization of Harness Reporting <a class="header-anchor" href="#_7-4-normalization-of-harness-reporting" aria-label="Permalink to &quot;7.4 Normalization of Harness Reporting&quot;">​</a></h3><p><strong>Direction</strong>: Establish standards for harness disclosure in academic papers.</p><p><strong>Proposal</strong>: Adoption of HarnessCard or equivalent in agent-related publications.</p><p><strong>Expected impact</strong>: Improved reproducibility, clearer attribution, cumulative progress.</p><h3 id="_7-5-layer-aware-baselines" tabindex="-1">7.5 Layer-Aware Baselines <a class="header-anchor" href="#_7-5-layer-aware-baselines" aria-label="Permalink to &quot;7.5 Layer-Aware Baselines&quot;">​</a></h3><p><strong>Direction</strong>: Build evaluation baselines that vary harness components systematically.</p><p><strong>Questions</strong>:</p><ul><li>What is the performance impact of varying control policies while holding model and agency fixed?</li><li>What is the impact of different runtime strategies?</li><li>How do these effects interact?</li></ul><p><strong>Method</strong>: Ablation studies controlling for one CAR layer while varying others.</p><h2 id="_8-limitations-and-caveats" tabindex="-1">8. Limitations and Caveats <a class="header-anchor" href="#_8-limitations-and-caveats" aria-label="Permalink to &quot;8. Limitations and Caveats&quot;">​</a></h2><h3 id="_8-1-scope-and-evidence" tabindex="-1">8.1 Scope and Evidence <a class="header-anchor" href="#_8-1-scope-and-evidence" aria-label="Permalink to &quot;8.1 Scope and Evidence&quot;">​</a></h3><ul><li><strong>Evidence bias</strong>: Audit tilts toward English-language, high-resource settings</li><li><strong>Selective argument</strong>: Not an exhaustive field survey but targeted analysis</li><li><strong>Vocabulary drift</strong>: Different communities use different terminology (harness, scaffold, infrastructure, etc.)</li></ul><h3 id="_8-2-conceptual" tabindex="-1">8.2 Conceptual <a class="header-anchor" href="#_8-2-conceptual" aria-label="Permalink to &quot;8.2 Conceptual&quot;">​</a></h3><ul><li><strong>CAR decomposition is analytic</strong>: Proposed framework is useful but not settled ontology</li><li><strong>Boundary fuzziness</strong>: Some systems blur the lines between control, agency, and runtime</li><li><strong>Context dependence</strong>: CAR patterns vary by application domain</li></ul><h3 id="_8-3-attribution" tabindex="-1">8.3 Attribution <a class="header-anchor" href="#_8-3-attribution" aria-label="Permalink to &quot;8.3 Attribution&quot;">​</a></h3><ul><li><strong>Causal identification</strong>: Requires controlled ablations not yet systematically reported</li><li><strong>Interaction effects</strong>: Model, control, agency, and runtime effects interact in complex ways</li><li><strong>Generalization</strong>: Findings may not transfer to future domains or model families</li></ul><h2 id="_9-ethical-considerations" tabindex="-1">9. Ethical Considerations <a class="header-anchor" href="#_9-ethical-considerations" aria-label="Permalink to &quot;9. Ethical Considerations&quot;">​</a></h2><h3 id="_9-1-dual-use-risks" tabindex="-1">9.1 Dual-Use Risks <a class="header-anchor" href="#_9-1-dual-use-risks" aria-label="Permalink to &quot;9.1 Dual-Use Risks&quot;">​</a></h3><p>Improved harnesses enable both beneficial and harmful automation. Governance must be internal to harness design, not an afterthought.</p><p><strong>Examples</strong>:</p><ul><li>A well-designed harness for autonomous code generation can also enable malicious code injection</li><li>Runtime controls that prevent accidental deletions can also restrict legitimate operations</li><li>Memory persistence enables learning from past mistakes but also enables potential unauthorized data accumulation</li></ul><h3 id="_9-2-autonomy-and-transparency" tabindex="-1">9.2 Autonomy and Transparency <a class="header-anchor" href="#_9-2-autonomy-and-transparency" aria-label="Permalink to &quot;9.2 Autonomy and Transparency&quot;">​</a></h3><p>As harnesses improve, agents appear more autonomous while remaining dependent on infrastructure. Disclosure is critical for accountability.</p><p><strong>Concern</strong>: Misrepresenting the autonomy level of systems (overstating agent &quot;reasoning&quot; while understating harness role).</p><h3 id="_9-3-resource-concentration" tabindex="-1">9.3 Resource Concentration <a class="header-anchor" href="#_9-3-resource-concentration" aria-label="Permalink to &quot;9.3 Resource Concentration&quot;">​</a></h3><p>Sophisticated harness engineering requires substantial resources. Risk of capability concentration among well-resourced organizations.</p><h2 id="_10-conclusion" tabindex="-1">10. Conclusion <a class="header-anchor" href="#_10-conclusion" aria-label="Permalink to &quot;10. Conclusion&quot;">​</a></h2><p>The harness layer—control, agency, and runtime infrastructure—is essential to agent reliability and reproducibility. Academic literature currently underspecifies this layer compared to engineering practice. The proposed CAR framework, evidence audit, and HarnessCard disclosure mechanism provide tools for making harness engineering explicit and comparable.</p><p><strong>Core contributions</strong>:</p><ol><li>Conceptual framework (CAR) for analyzing harness structure</li><li>Evidence that harness improvements often drive reported gains</li><li>Proposed transparency standard (HarnessCard)</li><li>Research agenda for harness-layer studies</li><li>Call for normalization of harness reporting in academic papers</li></ol><p><strong>Expected outcomes</strong>:</p><ul><li>Improved reproducibility through harness specification</li><li>Clearer attribution of performance improvements</li><li>Cumulative progress in agent design</li><li>Recognition of harness engineering as a legitimate research domain</li></ul><h2 id="references" tabindex="-1">References <a class="header-anchor" href="#references" aria-label="Permalink to &quot;References&quot;">​</a></h2><p>Audit references (63 in-scope works) available in appendix. Notable citations include:</p><ul><li><strong>SWE-agent</strong> (Jimenez et al.): Demonstrates control-layer redesign effects</li><li><strong>Meta-Harness</strong> (Lee et al.): Automated harness optimization</li><li><strong>OS-Symphony</strong> (Zeng et al.): Natural-language harness specification</li><li><strong>Anthropic agent guidelines</strong>: Engineering-practice documentation</li><li><strong>OpenAI system prompt research</strong>: Control-layer effectiveness</li><li><strong>General Agent Evaluation</strong> (Zhu et al.): Agency standardization attempts</li></ul><hr><p><strong>Keywords</strong>: agent engineering, harness design, control layer, agency design, runtime governance, agent evaluation, reproducibility</p><p><strong>Citation</strong>: He, C., Zhou, X., Wang, D., Xu, H., Liu, W., &amp; Miao, C. (2026). Harness engineering for language agents: The harness layer as control, agency, and runtime. <em>Preprints</em>, 202603.1756.v2.</p>`,160)])])}const h=a(r,[["render",s]]);export{g as __pageData,h as default};
